// D-0025-L sanitized classifier input event. Change selectedEvent to switch test events.
const selectedEvent = 'manual_safe';

const events = {
  manual_safe: {
    event_id: '<EVENT_ID>',
    event_type: 'manual_runtime_test',
    summary: 'D-0025-L manual test-safe live classifier to Decision Packet preview, no deploy, no secrets, no Telegram, no workflow mutation, no automation loop.',
    touched_paths: [
      'docs/contracts/decision-packet-mapping-v1.md',
      'workflows/exports/2026-06-06_d0025l-live-classifier-mapping-preview-test-safe.redacted.json'
    ],
    runtime_flags: { manual_runtime_test: true, no_production_mutation: true, touched: true, detail: 'D-0025-L manual test only' },
    secrets_flags: { touched: false, detail: '' },
    deploy_flags: { touched: false, detail: '' },
    n8n_flags: {
      workflow_40_mutation: false,
      workflow_41_mutation: false,
      workflow_42_mutation: false,
      workflow_49_used: false,
      test_workflow_id: 56,
      touched: true,
      detail: 'test workflow 56 only'
    },
    automation_flags: { autonomous_worker: false, permanent_loop: false, touched: false, detail: '' }
  }
};

const event = events[selectedEvent] || events.manual_safe;
const event_context = {
  event_id: '<EVENT_ID>',
  source_repo: '<REPO>',
  source_commit: '<COMMIT_SHA>',
  source_workflow: '<WORKFLOW_ID>',
  summary: event.summary,
  test_id: selectedEvent
};

return [{
  json: {
    ...event,
    selectedEvent,
    event_context,
    test_id: selectedEvent,
    test_only: true,
    manual_only: true,
    no_permanent_automation: true
  }
}];

// Validate live classifier HTTP response; fail-closed per mapping contract.
const ALLOWED_ROUTES = ['auto_allowed', 'human_gate', 'blocked'];
const ALLOWED_RISK = ['low', 'medium', 'high'];
const ALLOWED_CONF = ['low', 'medium', 'high'];

function isValidClassifier(c) {
  if (!c || typeof c !== 'object' || Array.isArray(c)) return false;
  const req = ['risk', 'route', 'reason', 'confidence', 'requires_human'];
  for (const k of req) {
    if (!Object.prototype.hasOwnProperty.call(c, k)) return false;
  }
  if (!ALLOWED_ROUTES.includes(String(c.route))) return false;
  if (!ALLOWED_RISK.includes(String(c.risk))) return false;
  if (!ALLOWED_CONF.includes(String(c.confidence))) return false;
  if (typeof c.reason !== 'string' || c.reason.length === 0) return false;
  if (typeof c.requires_human !== 'boolean') return false;
  return true;
}

function failClosed(reason) {
  return {
    risk: 'high',
    route: 'human_gate',
    requires_human: true,
    confidence: 'low',
    reason: reason || 'fallback:live_classifier_mapping_preview_invalid_or_unavailable'
  };
}

const prior = $('Build classifier test event').first().json;
const event_context = prior.event_context || {
  event_id: '<EVENT_ID>',
  source_repo: '<REPO>',
  source_commit: '<COMMIT_SHA>',
  source_workflow: '<WORKFLOW_ID>',
  summary: prior.summary || 'D-0025-L manual test',
  test_id: prior.test_id || 'manual_safe'
};

const resp = $input.item.json;
let body = null;
let httpOk = false;

if (resp && resp.body !== undefined) {
  body = resp.body;
  const sc = resp.statusCode;
  httpOk = sc === 200 || sc === '200';
} else if (resp && typeof resp === 'object') {
  body = resp;
  httpOk = true;
}

if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch (e) { body = null; }
}

let synthesized = false;
let c;

if (!httpOk || !isValidClassifier(body)) {
  c = failClosed('fallback:live_classifier_mapping_preview_invalid_or_unavailable');
  synthesized = true;
} else {
  c = { ...body };
}

return {
  json: {
    test_id: event_context.test_id || prior.test_id || 'manual_safe',
    classifier_output: c,
    effective_classifier: c,
    fail_closed_synthesized: synthesized,
    event_context,
    http_valid: httpOk && !synthesized,
    test_only: true,
    manual_only: true,
    no_permanent_automation: true
  }
};

// Build Decision Packet preview per docs/contracts/decision-packet-mapping-v1.md
const ALLOWED_ROUTES = ['auto_allowed', 'human_gate', 'blocked'];
const ALLOWED_RISK = ['low', 'medium', 'high'];
const ALLOWED_CONF = ['low', 'medium', 'high'];

function isValidClassifier(c) {
  if (!c || typeof c !== 'object' || Array.isArray(c)) return false;
  const req = ['risk', 'route', 'reason', 'confidence', 'requires_human'];
  for (const k of req) {
    if (!Object.prototype.hasOwnProperty.call(c, k)) return false;
  }
  if (!ALLOWED_ROUTES.includes(String(c.route))) return false;
  if (!ALLOWED_RISK.includes(String(c.risk))) return false;
  if (!ALLOWED_CONF.includes(String(c.confidence))) return false;
  if (typeof c.reason !== 'string' || c.reason.length === 0) return false;
  if (typeof c.requires_human !== 'boolean') return false;
  return true;
}

function failClosed(reason) {
  return {
    risk: 'high',
    route: 'human_gate',
    requires_human: true,
    confidence: 'low',
    reason: reason || 'fallback:live_classifier_mapping_preview_invalid_or_unavailable'
  };
}

function buildOptions() {
  return [
    '1 — Do not proceed; keep manual mode',
    '2 — Review manually and decide the next bounded step',
    '3 — Authorize a supervised, scope-limited next step'
  ];
}

function recommendationFor(route) {
  if (route === 'blocked') {
    return 'Raccomandazione: 1 — Do not proceed; keep manual mode unless explicit override context exists.';
  }
  return 'Raccomandazione: 2 — Review manually and decide the next bounded step.';
}

function perché(route, c) {
  if (route === 'blocked') {
    return 'Classifier route is blocked — do not proceed without explicit human override.';
  }
  if (c.confidence === 'low') {
    return 'Classifier confidence is low — fail-closed human review required.';
  }
  if (c.risk === 'high') {
    return 'Classifier risk is high — human review required before any proceed.';
  }
  return 'Classifier requires human gate — no silent auto-proceed for this event context.';
}

function buildPacket(c, eventCtx, testId) {
  const provenance = [
    'event_id=' + eventCtx.event_id,
    'repo=' + eventCtx.source_repo,
    'commit=' + eventCtx.source_commit,
    'source=' + eventCtx.source_workflow,
    'test=' + testId
  ].join('; ');
  return {
    ID: 'D-0025-L-T',
    Kind: 'runtime',
    Contesto: 'Live classifier test "' + testId + '": ' + eventCtx.summary + ' Classifier route ' + c.route + '; risk ' + c.risk + '.',
    'Perché serve decisione': perché(c.route, c),
    Opzioni: buildOptions(),
    Raccomandazione: recommendationFor(c.route),
    'Rischio principale': 'Proceeding without human boundary check may expand scope or touch forbidden runtime despite ' + c.risk + ' risk signal.',
    'Micro-interazioni eliminate': 'Manual copy/paste of live classifier JSON into Decision Packet shape.',
    'Scelta richiesta': 'Scrivi: 1 / 2 / 3',
    'Cosa NON viene fatto': 'No runtime, no Telegram send, no workflow mutation, no PM-34 unlock, no deploy/rollback, no secrets written, no automatic loop.',
    'Riferimento evento / provenienza': provenance,
    Risk: c.risk,
    Route: c.route,
    requires_human: c.requires_human,
    Confidence: c.confidence,
    'Classifier reason': c.reason
  };
}

const inp = $input.item.json;
let raw = inp.classifier_output;
let synthesized = inp.fail_closed_synthesized === true;
let c;

if (!isValidClassifier(raw)) {
  c = failClosed('fallback:live_classifier_mapping_preview_invalid_or_unavailable');
  synthesized = true;
} else {
  c = { ...raw };
}

const noPacketEligible =
  !synthesized &&
  c.route === 'auto_allowed' &&
  c.requires_human === false &&
  c.confidence !== 'low' &&
  c.risk !== 'high';

if (noPacketEligible) {
  return {
    json: {
      test_id: inp.test_id,
      preview_status: 'NO_PACKET_NO_ACTION',
      packet_present: false,
      packet: null,
      effective_classifier: c,
      fail_closed_synthesized: false,
      event_context: inp.event_context,
      test_only: true,
      manual_only: true,
      no_permanent_automation: true
    }
  };
}

let packetClassifier = { ...c };
if (c.confidence === 'low' || c.requires_human === true || c.risk === 'high') {
  if (c.route !== 'blocked') {
    packetClassifier.route = 'human_gate';
  }
}
if (synthesized) {
  packetClassifier = { ...c };
}
if (packetClassifier.route === 'auto_allowed') {
  packetClassifier.route = 'human_gate';
}

const packet = buildPacket(packetClassifier, inp.event_context, inp.test_id);

return {
  json: {
    test_id: inp.test_id,
    preview_status: 'PACKET_PREVIEW',
    packet_present: true,
    packet,
    effective_classifier: packetClassifier,
    fail_closed_synthesized: synthesized,
    event_context: inp.event_context,
    test_only: true,
    manual_only: true,
    no_permanent_automation: true
  }
};

// Read-only inspect / normalize live mapping preview output
const d = $input.item.json;
const ALLOWED = ['auto_allowed', 'human_gate', 'blocked'];

function routeCheck() {
  if (d.packet_present && d.packet && d.packet.Route) {
    return ALLOWED.includes(String(d.packet.Route));
  }
  if (d.effective_classifier && d.effective_classifier.route) {
    if (d.preview_status === 'NO_PACKET_NO_ACTION') {
      return d.effective_classifier.route === 'auto_allowed';
    }
    return ALLOWED.includes(String(d.effective_classifier.route));
  }
  return false;
}

return {
  json: {
    test_id: d.test_id,
    preview_status: d.preview_status,
    packet_present: d.packet_present,
    packet: d.packet,
    effective_classifier: d.effective_classifier,
    fail_closed_synthesized: d.fail_closed_synthesized === true,
    checks: {
      route_in_allowed_set: routeCheck(),
      no_send_performed: true,
      no_secret_placeholders_only: true,
      live_classifier_called_by_http_node_expected: true,
      no_telegram_node_expected: true,
      no_webhook_expected: true,
      no_schedule_expected: true,
      manual_only: true,
      no_permanent_automation: true
    },
    test_only: true,
    manual_only: true,
    no_permanent_automation: true
  }
};
